#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ValidatedEmail(String);

#[derive(Debug, thiserror::Error)]
pub enum EmailValidationError {
    #[error("Email cannot be empty")]
    Empty,
    #[error("Email must contain an '@' symbol")]
    MissingAtSymbol,
    #[error("Email is too long (max {max} characters, got {actual})")]
    TooLong { max: usize, actual: usize },
}

const MAX_EMAIL_LENGTH: usize = 254;

impl ValidatedEmail {
    pub fn parse(input: String) -> Result<Self, EmailValidationError> {
        let trimmed = input.trim().to_string();

        if trimmed.is_empty() {
            return Err(EmailValidationError::Empty);
        }

        if trimmed.len() > MAX_EMAIL_LENGTH {
            return Err(EmailValidationError::TooLong {
                max: MAX_EMAIL_LENGTH,
                actual: trimmed.len(),
            });
        }

        if !trimmed.contains('@') {
            return Err(EmailValidationError::MissingAtSymbol);
        }

        Ok(Self(trimmed))
    }

    pub fn as_str(&self) -> &str {
        &self.0
    }
}

impl std::fmt::Display for ValidatedEmail {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        self.0.fmt(f)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn valid_email_is_accepted() {
        let email = ValidatedEmail::parse("user@example.com".to_string());
        assert!(email.is_ok());
        assert_eq!(email.unwrap().as_str(), "user@example.com");
    }

    #[test]
    fn empty_email_is_rejected() {
        let email = ValidatedEmail::parse("".to_string());
        assert!(matches!(email, Err(EmailValidationError::Empty)));
    }

    #[test]
    fn whitespace_only_email_is_rejected() {
        let email = ValidatedEmail::parse("   ".to_string());
        assert!(matches!(email, Err(EmailValidationError::Empty)));
    }

    #[test]
    fn email_without_at_symbol_is_rejected() {
        let email = ValidatedEmail::parse("userexample.com".to_string());
        assert!(matches!(email, Err(EmailValidationError::MissingAtSymbol)));
    }

    #[test]
    fn email_longer_than_254_chars_is_rejected() {
        let long_email = format!("{}@example.com", "a".repeat(250));
        let email = ValidatedEmail::parse(long_email.clone());
        assert!(matches!(
            email,
            Err(EmailValidationError::TooLong { max: 254, .. })
        ));
    }

    #[test]
    fn email_is_trimmed() {
        let email = ValidatedEmail::parse("  user@example.com  ".to_string());
        assert!(email.is_ok());
        assert_eq!(email.unwrap().as_str(), "user@example.com");
    }
}

